import React, { createContext, useContext, useState, useEffect } from 'react';

const CalendarContext = createContext();

export const CalendarProvider = ({ children }) => {
    const [tasks, setTasks] = useState({});
    const [currentDate, setCurrentDate] = useState(new Date());
    const [isCalendarExpanded, setIsCalendarExpanded] = useState(false);
    const [selectedTask, setSelectedTask] = useState(null);

    // Add debug logging for state changes
    useEffect(() => {
        console.log('Calendar Context State:', {
            taskCount: Object.keys(tasks).reduce((acc, date) => acc + tasks[date].length, 0),
            currentDate,
            isCalendarExpanded,
            selectedTask
        });
    }, [tasks, currentDate, isCalendarExpanded, selectedTask]);

    const addTask = async (task, isManualAdd = false) => {
        console.log('Adding task:', { task, isManualAdd });
        try {
            // Format the task data to match backend expectations
            const taskData = {
                date: task.startDate,  // Backend expects 'date' field
                title: task.title,
                description: task.description || task.title,
                time: task.time || '',
                color: task.color || '#007bff',  // Default color if none provided
                startDate: task.startDate,
                endDate: task.endDate || task.startDate,
                recurrence: task.recurrence || null,
                recurrenceEnd: task.recurrenceEnd || null,
                group_id: task.group_id || String(Date.now())  // Ensure group_id exists
            };

            console.log('Sending task to backend:', taskData);

            // For manual adds, we don't need to confirm through the AI endpoint
            const endpoint = isManualAdd ? '/api/tasks' : '/api/confirm-task';
            
            const response = await fetch(`http://localhost:5000${endpoint}`, {
                method: 'POST',
                headers: { 
                    'Content-Type': 'application/json',
                    'Accept': 'application/json'
                },
                body: JSON.stringify(taskData)
            });

            if (!response.ok) {
                const errorData = await response.json();
                console.error('Server error:', errorData);
                throw new Error(errorData.error || 'Failed to add task');
            }

            const result = await response.json();
            
            // Update local state with the confirmed task
            setTasks(prev => {
                const date = taskData.startDate;
                const updatedTasks = { ...prev };
                if (!updatedTasks[date]) {
                    updatedTasks[date] = [];
                }
                updatedTasks[date] = [...updatedTasks[date], taskData];
                return updatedTasks;
            });

            return true;
        } catch (error) {
            console.error('Error adding task:', error);
            throw error;
        }
    };

    const updateTask = async (date, groupId, updatedTask) => {
        console.log('Updating task:', { date, groupId, updatedTask });
        try {
            const response = await fetch(`http://localhost:5000/api/tasks/${date}/${groupId}`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Accept': 'application/json'
                },
                body: JSON.stringify(updatedTask)
            });

            if (!response.ok) {
                throw new Error('Failed to update task');
            }

            const result = await response.json();
            
            // Update local state
            setTasks(prev => {
                const updatedTasks = { ...prev };
                if (updatedTasks[date]) {
                    updatedTasks[date] = updatedTasks[date].map(t => 
                        t.group_id === groupId ? { ...t, ...updatedTask } : t
                    );
                }
                return updatedTasks;
            });

            return true;
        } catch (error) {
            console.error('Error updating task:', error);
            throw error;
        }
    };

    const deleteTask = async (groupId) => {
        console.log('Deleting task:', groupId);
        try {
            const response = await fetch(`http://localhost:5000/api/tasks/${groupId}`, {
                method: 'DELETE',
                headers: {
                    'Accept': 'application/json'
                }
            });

            if (!response.ok) {
                throw new Error('Failed to delete task');
            }

            // Update local state
            setTasks(prev => {
                const updatedTasks = { ...prev };
                for (const date in updatedTasks) {
                    updatedTasks[date] = updatedTasks[date].filter(t => t.group_id !== groupId);
                    if (updatedTasks[date].length === 0) {
                        delete updatedTasks[date];
                    }
                }
                return updatedTasks;
            });

            return true;
        } catch (error) {
            console.error('Error deleting task:', error);
            throw error;
        }
    };

    const value = {
        tasks,
        currentDate,
        setCurrentDate,
        addTask,
        updateTask,
        deleteTask,
        isCalendarExpanded,
        setIsCalendarExpanded,
        selectedTask,
        setSelectedTask
    };

    return (
        <CalendarContext.Provider value={value}>
            {children}
        </CalendarContext.Provider>
    );
};

export const useCalendar = () => {
    const context = useContext(CalendarContext);
    if (!context) {
        throw new Error('useCalendar must be used within a CalendarProvider');
    }
    return context;
};
